#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 huv=uTexSize.zw*0.5;
vec2 aspc=vec2(q2,q1);
vec4 tuv;
vec3 pq;
vec3 my_scale,cnt;
vec3 st,op,prj,prjN,surfp,sref,b2,bpr,b3;
vec4 pln;
float mscale,i,cp,sp,pdist;
my_scale=texture(sampler_pw_main,vec2(q20,0.007));
mscale=1/(my_scale.z);
st.xy=(vUvOriginal.xy-0.5)*(2.5+(q3+1)*4)*aspc+vec3(q4,q5,q6)*0.8; //front plane
st.z=1+q3;
op.xy=st.xy*(2.2+my_scale.y*mscale*0.1)+vec3(q4,q5,q6)*0.8; //back plane
op.z=-1+q3;
op=multiply(op,rot_f1);
sref=op;
st=multiply(st,rot_f1);
op+=vec3(q3,q4,q5)*0.4;
st+=vec3(q3,q4,q5)*0.4;
pdist=-10;
prj=op-st;
prjN=normalize(prj);
tuv=-150;
pln.z=prjN.z; //dot on z
pln.w=op.z;
surfp=prjN*(1/pln.zzz);
pln.xy=op.xy-surfp.xy*(pln.w+0.5).xx;
bpr.z=prjN.z;
bpr.xy=op.xy-surfp.xy*(pln.w-5).xx;
cnt.xyz=pln.z>0?((abs(bpr.x)<=5)&&(abs(bpr.y)<=5)?bpr.xyz:-50):-50;
tuv.xyzw=pln.z>0?((abs(pln.x)<=0.5)&&(abs(pln.y)<=0.5)?pln.xyzw:tuv):tuv;
pln.zw=-pln.zw;
pln.xy=op.xy+surfp.xy*(pln.w+0.5).xx;
bpr.xy=op.xy+surfp.xy*(pln.w-5).xx;
cnt.xyz=pln.z>0?((abs(bpr.x)<=5)&&(abs(bpr.y)<=5)?bpr.xyz:cnt):cnt;
tuv.xyzw=pln.z>0?( (abs(pln.x)<=0.5)&&(abs(pln.y)<=0.5)?pln.xyzw:tuv):tuv;
pln.y=prjN.y;
pln.w=op.y;
surfp=prjN*(1/pln.yyy);
pln.xz=op.xz-surfp.xz*(pln.w+0.5).xx;
bpr.z=prjN.y;
bpr.xy=op.xz-surfp.xz*(pln.w-5).xx;
cnt.xyz=pln.y>0?((abs(bpr.x)<=5)&&(abs(bpr.y)<=5)?bpr.xyz:cnt):cnt;
tuv.xyzw=pln.y>0?((abs(pln.x)<=0.5)&&(abs(pln.z)<=0.5)?pln.xzyw:tuv):tuv;
pln.yw=-pln.yw;
pln.xz=op.xz+surfp.xz*(pln.w+0.5).xx;
bpr.xy=op.xz+surfp.xz*(pln.w-5).xx;
cnt.xyz=pln.y>0?((abs(bpr.x)<=5)&&(abs(bpr.y)<=5)?bpr.xyz:cnt):cnt;
tuv.xyzw=pln.y>0?( (abs(pln.x)<=0.5)&&(abs(pln.z)<=0.5)?pln.xzyw:tuv):tuv;
pln.x=prjN.x;
pln.w=op.x;
surfp=prjN*(1/pln.xxx);
pln.yz=op.yz-surfp.yz*(pln.w+0.5).xx;
bpr.z=prjN.x;
bpr.xy=op.yz-surfp.yz*(pln.w-5).xx;
cnt.xyz=pln.x>0?((abs(bpr.x)<5)&&(abs(bpr.y)<5)?bpr.xyz:cnt):cnt;
tuv.xyzw=pln.x>0?( (abs(pln.y)<0.5)&&(abs(pln.z)<0.5)?pln.yzxw:tuv):tuv;
pln.xw=-pln.xw;
pln.yz=op.yz+surfp.yz*(pln.w+0.5).xx;
bpr.xy=op.yz+surfp.yz*(pln.w-5).xx;
cnt.xyz=pln.x>0?((abs(bpr.x)<5)&&(abs(bpr.y)<5)?bpr.xyz:cnt):cnt;
tuv.xyz=pln.x>0?( (abs(pln.y)<0.5)&&(abs(pln.z)<0.5)?pln.yzx:tuv):tuv;
sp=tuv.x;
vec3 t1,t2,a1,a2;
b2=texture(base02,cnt.xy*0.1+0.5);
b3=texture(base01,vUvOriginal);
pdist=0.33333*(b2.x+b2.y+b2.z);
i=texture(sampler_pw_main,vec2(q20+vUvOriginal.x,pdist+vUvOriginal.y)).x;
i=i>my_scale.y*0.5?i*mscale:i+my_scale.y*0.5*mscale;
i=min(i,1);
cp=i;
pln=tuv.z>0?texture(base02,0.5+tuv):0;
ret=b2;// *((1-i)*0.6);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUvOriginal.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y -= (noise9).x*.5;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x -= (noise9).z*.5;

ret=tuv.z>0?pln.xyz*(0.9+(i*0.1)):ret;


  fragColor = ret;
}

